import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './Navbar.css';

function Navbar() {
  const navigate = useNavigate();
  const isAuthenticated = !!localStorage.getItem('token');

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <nav className="navbar">
      <div className="nav-top">
        <div className="nav-top-container">
          <div className="nav-top-left">
            <span>📅 {new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}</span>
            <span>|</span>
            <span>Safety | Security | Punctuality</span>
          </div>
          <div className="nav-top-right">
            <a href="#alerts">ALERTS</a>
            <a href="#contact">CONTACT US</a>
            <span>हिंदी</span>
          </div>
        </div>
      </div>
      <div className="nav-main">
        <div className="nav-container">
          <div className="nav-logo-section">
            <Link to="/" className="nav-logo">
              <div className="logo-icon">🚂</div>
              <div className="logo-text">
                <div className="logo-main">INDIAN RAILWAYS</div>
                <div className="logo-sub">Safety | Security | Punctuality</div>
              </div>
            </Link>
          </div>
          <ul className="nav-menu">
            <li><Link to="/">Home</Link></li>
            <li><Link to="/search">Trains</Link></li>
            <li><Link to="/pnr">PNR Status</Link></li>
            {isAuthenticated && (
              <>
                <li><Link to="/dashboard">My Bookings</Link></li>
                <li><Link to="/ai-features">AI Features</Link></li>
                <li><button onClick={handleLogout} className="btn-logout">Logout</button></li>
              </>
            )}
            {!isAuthenticated && (
              <>
                <li><Link to="/login">Login</Link></li>
                <li><Link to="/signup">Register</Link></li>
              </>
            )}
          </ul>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
